const norm=(s)=>(s||'').replace(/ /g,' ').replace(/\s+/g,' ').trim();
const ded=(s)=>{if(!s)return s;const n=s.length;if(n%2===0){const h=s.slice(0,n/2);if(h===s.slice(n/2))return h.trim();}return s;};
const PH=/show your qualifications|recruiter inmail|2x more likely|^school$|degree, field of study|^add (a |an )?\w|^field of study|enhance profile|verify where you/i;
const name=norm((document.title||'').split(' | ')[0]);
const skip=/^(0 notifications|Skip to|Home|My Network|Jobs|Messaging|Notifications|Me|For Business|Try Premium|Enhance profile|Add section|Add profile|Open to|Add verification|More|Message|Connect|Follow|Pending|·|\d+(\s|$))/i;
const bodyLines=[];const seenL=new Set();
(document.body.innerText||'').split('\n').forEach((l)=>{l=ded(norm(l));if(l&&!seenL.has(l)){seenL.add(l);bodyLines.push(l);}});
let headline='',loc='';const ni=bodyLines.indexOf(name);
for(let i=(ni>=0?ni+1:0);i<bodyLines.length;i++){const l=bodyLines[i];if(!l||l===name||skip.test(l))continue;if(!headline){headline=l;continue;}if(!loc&&l.indexOf(',')>=0&&l.length<90){loc=l;break;}}
const h2s=[...document.querySelectorAll('h2')];
const secByLabel=(label)=>h2s.find((h)=>norm(ded(h.innerText||''))===label)||null;
const cardOf=(h2)=>{let el=h2;for(let i=0;i<6;i++){if(!el.parentElement)break;el=el.parentElement;if((el.innerText||'').length>(norm(h2.innerText||'').length+40))return el;}return h2.parentElement||h2;};
const entriesFrom=(label)=>{const h=secByLabel(label);if(!h)return [];const card=cardOf(h);const res=[];const pushE=(lines)=>{const dd=[];for(const l of lines){const x=ded(norm(l));if(x&&dd[dd.length-1]!==x&&!/^(show all|see more|·)/i.test(x)&&!PH.test(x))dd.push(x);}const take=dd.slice(0,3).join(' — ');if(take&&!PH.test(take)&&res.indexOf(take)<0)res.push(take);};const lis=[...card.querySelectorAll('li')];if(lis.length){for(const li of lis){pushE((li.innerText||'').split('\n'));if(res.length>=8)break;}}else{const lines=(card.innerText||'').split('\n').map((l)=>ded(norm(l))).filter(Boolean);const hi=lines.indexOf(norm(label));const after=hi>=0?lines.slice(hi+1):lines;for(let i=0;i<after.length&&res.length<8;i+=3){pushE(after.slice(i,i+3));}}return res.slice(0,8);};
const aboutH=secByLabel('About');let about='';if(aboutH){const card=cardOf(aboutH);about=norm((card.innerText||'').replace(/^About\s*/i,''));if(PH.test(about))about='';if(about.length>1500)about=about.slice(0,1500);}
const experience=entriesFrom('Experience');
const education=entriesFrom('Education');
return {profile_url:location.href,name:name,headline:headline,location:loc,about:about,experience:experience,education:education};
